import React, { useState, useEffect } from 'react';
import { supabase } from './lib/supabase';
import { Calendar, Users, Plus, Clock, MapPin, Apple, Search, ChevronRight } from 'lucide-react';

function App() {
  const [view, setView] = useState<'classes' | 'users'>('classes');
  const [loading, setLoading] = useState(false);
  const [classes, setClasses] = useState<any[]>([]);
  const [users, setUsers] = useState<any[]>([]);

  // Formulario Clase
  const [formData, setFormData] = useState({
    title: '', trainer: '', location: 'Box Principal', intensity: 'REGULAR',
    date: '', startTime: '10:00', endTime: '11:00', capacity: 15
  });

  useEffect(() => {
    fetchClasses();
    fetchUsers();
  }, []);

  const fetchClasses = async () => {
    const { data } = await supabase.from('classes').select('*').order('start_time', { ascending: false });
    if (data) setClasses(data);
  };

  const fetchUsers = async () => {
    const { data } = await supabase.from('profiles').select('*').order('first_name', { ascending: true });
    if (data) setUsers(data);
  };

  const handleSubmitClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const startDateTime = `${formData.date}T${formData.startTime}:00Z`;
    const endDateTime = `${formData.date}T${formData.endTime}:00Z`;

    const { error } = await supabase.from('classes').insert([{
      title: formData.title,
      trainer: formData.trainer,
      location: formData.location,
      intensity_badge: formData.intensity,
      start_time: startDateTime,
      end_time: endDateTime,
      max_capacity: formData.capacity
    }]);

    if (!error) {
      alert("Clase creada");
      setFormData({ ...formData, title: '', trainer: '' });
      fetchClasses();
    }
    setLoading(false);
  };

  return (
    <div className="min-h-screen bg-[#09090b] text-white">
      {/* Sidebar Lateral Simulado */}
      <div className="flex">
        <nav className="w-64 h-screen bg-zinc-900 border-r border-zinc-800 p-6 fixed">
          <h1 className="text-2xl font-bold text-neon mb-10 text-[#39FF14]">GYM ADMIN</h1>
          <div className="space-y-4">
            <button 
              onClick={() => setView('classes')}
              className={`w-full flex items-center gap-3 p-3 rounded-xl transition ${view === 'classes' ? 'bg-neon/10 text-[#39FF14]' : 'text-zinc-400 hover:bg-zinc-800'}`}
            >
              <Calendar size={20} /> Calendario
            </button>
            <button 
              onClick={() => setView('users')}
              className={`w-full flex items-center gap-3 p-3 rounded-xl transition ${view === 'users' ? 'bg-neon/10 text-[#39FF14]' : 'text-zinc-400 hover:bg-zinc-800'}`}
            >
              <Users size={20} /> Usuarios
            </button>
          </div>
        </nav>

        {/* Contenido Principal */}
        <main className="flex-1 ml-64 p-10">

          {view === 'classes' ? (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-1">
                <h2 className="text-2xl font-bold mb-6">Programar Clase</h2>
                <form onSubmit={handleSubmitClass} className="bg-zinc-900 p-6 rounded-3xl border border-zinc-800 space-y-4">
                  {/* ... (Inputs del formulario anterior) ... */}
                  <input className="w-full bg-zinc-800 border border-zinc-700 rounded-xl p-3" placeholder="Título" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />
                  <input className="w-full bg-zinc-800 border border-zinc-700 rounded-xl p-3" placeholder="Trainer" value={formData.trainer} onChange={e => setFormData({...formData, trainer: e.target.value})} />
                  <input type="date" className="w-full bg-zinc-800 border border-zinc-700 rounded-xl p-3" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} />
                  <div className="flex gap-2">
                    <input type="time" className="flex-1 bg-zinc-800 border border-zinc-700 rounded-xl p-3" value={formData.startTime} onChange={e => setFormData({...formData, startTime: e.target.value})} />
                    <input type="time" className="flex-1 bg-zinc-800 border border-zinc-700 rounded-xl p-3" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} />
                  </div>
                  <button className="w-full bg-[#39FF14] text-black font-bold py-3 rounded-xl">PUBLICAR</button>
                </form>
              </div>

              <div className="lg:col-span-2">
                <h2 className="text-2xl font-bold mb-6">Próximas Clases</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {classes.map(c => (
                    <div key={c.id} className="bg-zinc-900 p-5 rounded-2xl border border-zinc-800">
                      <h3 className="font-bold text-lg">{c.title}</h3>
                      <p className="text-zinc-500 text-sm mb-4">Coach: {c.trainer}</p>
                      <div className="flex items-center gap-4 text-xs text-zinc-400">
                        <span className="flex items-center gap-1"><Clock size={12}/> {new Date(c.start_time).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                        <span className="flex items-center gap-1"><MapPin size={12}/> {c.location}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <div>
              <h2 className="text-2xl font-bold mb-6">Gestión de Usuarios</h2>
              <div className="bg-zinc-900 rounded-3xl border border-zinc-800 overflow-hidden">
                <table className="w-full text-left">
                  <thead className="bg-zinc-800/50 text-zinc-500 text-xs uppercase">
                    <tr>
                      <th className="p-4">Usuario</th>
                      <th className="p-4">ID</th>
                      <th className="p-4">Acciones</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-zinc-800">
                    {users.map(u => (
                      <tr key={u.id} className="hover:bg-zinc-800/30 transition">
                        <td className="p-4 flex items-center gap-3">
                          <div className="w-10 h-10 bg-neon/20 rounded-full flex items-center justify-center text-neon font-bold text-[#39FF14]">
                            {u.first_name[0]}{u.last_name[0]}
                          </div>
                          <div>
                            <p className="font-bold">{u.first_name} {u.last_name}</p>
                          </div>
                        </td>
                        <td className="p-4 text-xs text-zinc-500 font-mono">{u.id.substring(0,8)}...</td>
                        <td className="p-4">
                          <button 
                            className="flex items-center gap-2 bg-zinc-800 hover:bg-neon hover:text-black px-4 py-2 rounded-lg text-sm font-bold transition"
                            onClick={() => alert(`Próximamente: Gestionar nutrición para ${u.first_name}`)}
                          >
                            <Apple size={16} /> Planificar Dieta
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

export default App;
